INSERT INTO `products` VALUES (1,'lajzzjrkhc7n17pdc5t315r0','雷达流速仪','[{\"type\": \"paragraph\", \"children\": [{\"text\": \"是一款针对水面流速测量的非接触式雷达流速测量设备。采用单发单收微带天线形式，发射连续波（CW）信号，接收目标反射回波信号，以测量流动目标的实时速度。设备具备自动调频功能，可有效抵抗同频信号干扰，具备角度补偿及独特滤波算法，流速测量稳定准确。设备安装维护容易，操作简单，可广泛适用于渠道及天然河道的表面流速测定。\", \"type\": \"text\"}]}]','[\"低速率、高精度目标检测\", \"设备体积小、重量轻、功耗低\", \"全天候测量\"]',NULL,'2026-03-26 03:44:34.976000','2026-03-26 03:44:35.842000',NULL,1,1,NULL),(2,'lajzzjrkhc7n17pdc5t315r0','雷达流速仪','[{\"type\": \"paragraph\", \"children\": [{\"text\": \"是一款针对水面流速测量的非接触式雷达流速测量设备。采用单发单收微带天线形式，发射连续波（CW）信号，接收目标反射回波信号，以测量流动目标的实时速度。设备具备自动调频功能，可有效抵抗同频信号干扰，具备角度补偿及独特滤波算法，流速测量稳定准确。设备安装维护容易，操作简单，可广泛适用于渠道及天然河道的表面流速测定。\", \"type\": \"text\"}]}]','[\"低速率、高精度目标检测\", \"设备体积小、重量轻、功耗低\", \"全天候测量\"]',NULL,'2026-03-26 03:44:34.976000','2026-03-26 03:44:35.842000','2026-03-26 03:44:35.857000',1,1,NULL);
